"use strict";(self.webpackChunknpy_notebook=self.webpackChunknpy_notebook||[]).push([[1477],{10:r=>{r.exports=JSON.parse('{"blogPosts":[{"id":"/PyTroch\u57fa\u7840","metadata":{"permalink":"/blog/PyTroch\u57fa\u7840","source":"@site/blog/PyTroch\u57fa\u7840.md","title":"PyTorch\u57fa\u7840","description":"\u4e00\u3001\u5e38\u7528\u51fd\u6570\u90e8\u5206","date":"2023-04-18T10:22:37.000Z","formattedDate":"2023\u5e744\u670818\u65e5","tags":[],"hasTruncateMarker":false,"authors":[],"frontMatter":{},"nextItem":{"title":"\u57fa\u7840\u6570\u5b66\u77e5\u8bc6","permalink":"/blog/\u6570\u5b66\u57fa\u7840"}},"content":"## \u4e00\u3001\u5e38\u7528\u51fd\u6570\u90e8\u5206\\r\\n\\r\\n1. concat\u4e0estack\u51fd\u6570\\r\\n\\r\\n   stack\u51fd\u6570\u5bf9\u8f93\u5165\u7684\u4e24\u4e2a\u5f20\u91cf\u5728\u6307\u5b9a\u7684\u7ef4\u5ea6\u8fdb\u884c\u5806\u53e0\uff0c\u662f==\u521b\u5efa\u4e86\u65b0\u7684\u7ef4\u5ea6==\\r\\n\\r\\n   concat\u51fd\u6570\u5bf9\u8f93\u5165\u7684\u5f20\u91cf\u5728\u6307\u5b9a\u7ef4\u5ea6\u8fdb\u884c\u62fc\u63a5\uff0c\u6ca1\u6709\u521b\u5efa\u65b0\u7684\u7ef4\u5ea6\\r\\n\\r\\n   ```python\\r\\n   # stack\u548cconcat\u51fd\u6570\\r\\n   a = torch.rand(4, 3)  # A\u73ed4\u4f4d\u540c\u5b66\uff0c\u6bcf\u4f4d\u540c\u5b663\u79d1\u6210\u7ee9\\r\\n   b = torch.rand(4, 3)  # B\u73ed4\u4f4d\u540c\u5b66\uff0c\u6bcf\u4f4d\u540c\u5b663\u79d1\u6210\u7ee9\\r\\n   c = torch.stack((a, b), dim=0)  # \u7406\u89e3\uff1a\u5e74\u7ea7\u6240\u6709\u540c\u5b66\u76843\u79d1\u6210\u7ee9\uff08\u5047\u8bbe\u5e74\u7ea7\u53ea\u6709A\u73ed\u548cB\u73ed\u4e24\u4e2a\u73ed\uff0c\u6bcf\u4e2a\u73ed\u53ea\u6709\u56db\u540d\u540c\u5b66\uff09\\r\\n   print(c.shape)  # torch.Size([2, 4, 3])\\r\\n   d = torch.concat((a, b), dim=1)  # \u7406\u89e3\uff1aa\u662fA\u73ed4\u4f4d\u540c\u5b663\u79d1\u6210\u7ee9\uff0cb\u662f\u8fd94\u540d\u540c\u5b66\u5176\u4ed63\u95e8\u8bfe\u7684\u6210\u7ee9\uff0c\u62fc\u63a5\u540e\u4ee3\u8868\u8fd94\u540d\u540c\u5b66\u76846\u79d1\u6210\u7ee9\\r\\n   print(d.shape)  # torch.Size([4, 6])\\r\\n   ```\\r\\n\\r\\n2. list\u548ctensor\u4e58\u6cd5\u4e0d\u540c\u4e4b\u5904\\r\\n\\r\\n   list\u7684*\u4e58\u6cd5\u662f\u590d\u5236\u5143\u7d20\uff0c\u6539\u53d8list\u7684shape\\r\\n\\r\\n   tensor\u7684*\u4e58\u6cd5\u662f\u5bf9tensor\u4e2d\u7684\u5143\u7d20\u8fdb\u884c\u70b9\u4e58\u8ba1\u7b97\\r\\n\\r\\n   ```python\\r\\n   a = torch.tensor([[3, 3, 3, 3]])\\r\\n   b = [3]  # list\u7684*\u4e58\u662f\u590d\u5236\u5143\u7d20\u8fdb\u884c\u6269\u5c55\\r\\n   print(a * 3)  # tensor([[9, 9, 9, 9]])\\r\\n   print(b * 3)  # [3, 3, 3]\\r\\n   ```\\r\\n\\r\\n3. \u6700\u5927\u503c / \u6700\u5c0f\u503c\u7d22\u5f15\uff1aargmax / argmin\\r\\n\\r\\n   \u9700\u8981\u901a\u8fc7\u53c2\u6570dim\u6307\u5b9a\u64cd\u4f5c\u7684\u7ef4\u5ea6\uff0cdim\u7684\u7406\u89e3\\r\\n\\r\\n   - \u5b98\u65b9\u89e3\u91ca\uff1aThe dimension to reduce\\r\\n\\r\\n   - \u4ee5\u4e8c\u7ef4\u5f20\u91cf\u4e3e\u4f8b\uff0cdim=1\u5373\u5728\u6bcf\u4e00\u884c\u4e2d\u9009\u51fa\u4e00\u4e2a\u6700\u5927\u503c / \u6700\u5c0f\u503c\u5143\u7d20\u7684\u7d22\u5f15\uff0c\u7d22\u5f15\u7684shape\u5e94\u4e3a[dim0, 1]\uff0c\u5373reduce\u4e86dim=1\u7684\u7ef4\u5ea6\\r\\n\\r\\n   ```python\\r\\n   # \u6700\u5927\u503c\u6700\u5c0f\u503c\u7d22\u5f15\\r\\n   a = torch.tensor([[0.1, 0.9, 0.3], [0.9, 0.8, 0.99], [0.1, 0.7, 0.8], [0.88, 0.1, 0.2]])  # [4, 3]\\r\\n   print(\\"argmax output: \\", a.argmax(dim=0), a.argmax(dim=1))  # argmax output:  tensor([1, 0, 1]) tensor([1, 2, 2, 0])\\r\\n   ```\\r\\n\\r\\n4. Python zip\u51fd\u6570\\r\\n\\r\\n   zip\u51fd\u6570\u53ef\u4ee5\u7406\u89e3\u4e3a\u538b\u7f29\uff0c\u5c06\u8f93\u5165\u7684\u4e24\u4e2a\u8fed\u4ee3\u5668\u7684==\u6700\u5916\u5c42==\u5bf9\u5e94\u5143\u7d20\u538b\u7f29\u4e3a\u4e00\u4e2a\u65b0\u7684\u5143\u7d20\\r\\n\\r\\n   ```python\\r\\n   a = torch.tensor([1, 2, 3])\\r\\n   b = torch.tensor([4, 5, 6])\\r\\n   c = zip(a, b)\\r\\n   for i in c:\\r\\n       print(i)\\r\\n   \'\'\'\\r\\n   (tensor(1), tensor(4))\\r\\n   (tensor(2), tensor(5))\\r\\n   (tensor(3), tensor(6))\\r\\n   \'\'\'\\r\\n   a = torch.tensor([[1, 2, 3], [3, 2, 1]])\\r\\n   b = torch.tensor([[4, 5, 6], [6, 5, 4]])\\r\\n   c = zip(a, b)\\r\\n   for i in c:\\r\\n       print(i)\\r\\n   \'\'\'\\r\\n   (tensor([1, 2, 3]), tensor([4, 5, 6]))\\r\\n   (tensor([3, 2, 1]), tensor([6, 5, 4]))\\r\\n   \'\'\'\\r\\n   ```"},{"id":"/\u6570\u5b66\u57fa\u7840","metadata":{"permalink":"/blog/\u6570\u5b66\u57fa\u7840","source":"@site/blog/\u6570\u5b66\u57fa\u7840.md","title":"\u57fa\u7840\u6570\u5b66\u77e5\u8bc6","description":"\u77e9\u9635 / \u5411\u91cf\u7684\u5185\u79ef\u548c\u5916\u79ef","date":"2023-04-18T10:22:37.000Z","formattedDate":"2023\u5e744\u670818\u65e5","tags":[],"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"PyTorch\u57fa\u7840","permalink":"/blog/PyTroch\u57fa\u7840"},"nextItem":{"title":"\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","permalink":"/blog/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6"}},"content":"### \u77e9\u9635 / \u5411\u91cf\u7684\u5185\u79ef\u548c\u5916\u79ef\\r\\n\\r\\n1. **\u70b9\u4e58\uff1a**\u5185\u79ef\u53c8\u79f0\u6807\u91cf\u79ef\uff0c\u8fd0\u7b97\u7ed3\u679c\u4e3a\u6807\u91cf\uff0c\u662f\u5c06\u4e24\u4e2a\u77e9\u9635\u6216\u5411\u91cf\u7684\u5bf9\u5e94\u5143\u7d20\u505a\u4e58\u6cd5\\r\\n2. **\u53c9\u4e58\uff1a**\u5916\u79ef\u53c8\u79f0\u5411\u91cf\u79ef\uff0c\u8fd0\u7b97\u7ed3\u679c\u4e3a\u5411\u91cf\uff0c\u9075\u5faa\u884c\u5217\u5f0f\u4e58\u6cd5\u89c4\u5219"},{"id":"/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","metadata":{"permalink":"/blog/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","source":"@site/blog/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6.md","title":"\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","description":"\u4e00\u3001\u6fc0\u6d3b\u51fd\u6570","date":"2023-04-18T10:22:37.000Z","formattedDate":"2023\u5e744\u670818\u65e5","tags":[],"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"\u57fa\u7840\u6570\u5b66\u77e5\u8bc6","permalink":"/blog/\u6570\u5b66\u57fa\u7840"},"nextItem":{"title":"\u7406\u8bba\u57fa\u7840","permalink":"/blog/\u7406\u8bba\u77e5\u8bc6"}},"content":"## \u4e00\u3001\u6fc0\u6d3b\u51fd\u6570\\r\\n\\r\\n1. Sigmoid\u51fd\u6570 / Logistic\u51fd\u6570\\r\\n\\r\\n   $$\\r\\n   \\\\sigma(x) = \\\\frac{1}{1 + e^{-x}}\\r\\n   \\\\tag{1}\\r\\n   $$\\r\\n\\r\\n   $$\\r\\n   \\\\frac{{\\\\rm d}\\\\sigma}{{\\\\rm d}x} = \\\\sigma{(1 - \\\\sigma)}\\r\\n   \\\\tag{2}\\r\\n   $$\\r\\n\\r\\n\\r\\n   \u4f18\u70b9\uff1a\u53ef\u4ee5\u5c06\u6570\u636e\u538b\u7f29\u81f3[0, 1)\u533a\u95f4\u5185\uff0c\u6709\u8f83\u5927\u5b9e\u7528\u610f\u4e49\\r\\n\\r\\n   \u81f4\u547d\u95ee\u9898\uff1a\u5728\u8f93\u5165\u503c\u8f83\u5c0f\u6216\u8f83\u5927\u65f6\uff0cSigmoid\u51fd\u6570\u7684\u68af\u5ea6\u8d8b\u8fd1\u4e8e\u96f6\uff0c\u4f1a\u5bfc\u81f4\u7f51\u7edc\u53c2\u6570\u957f\u65f6\u95f4\u5f97\u4e0d\u5230\u66f4\u65b0\uff0c\u5373\u68af\u5ea6\u5f25\u6563\u95ee\u9898\\r\\n\\r\\n   ```python\\r\\n   from torch.nn import functional as F\\r\\n   import torch\\r\\n   x = torch.linspace(-100, 100, 10)\\r\\n   F.sigmoid(x)  # \u5f53x\u4e3a100\u65f6\uff0csigmoid(x)\u5c31\u63a5\u8fd1\u4e8e0\u4e86\\r\\n   ```\\r\\n\\r\\n2. \u7ebf\u6027\u6574\u6d41\u5355\u5143\uff08Rectified Linear Unit, ReLU\uff09\\r\\n   $$\\r\\n   f(x) = \\r\\n   \\\\begin{cases}\\r\\n   0 & x < 0\\\\\\\\\\r\\n   x & x \\\\geq 0\\\\\\\\\\r\\n   \\\\end{cases}\\r\\n   \\\\tag{1}\\r\\n   $$\\r\\n   $$\\r\\n   \\\\frac {{\\\\text d}f(x)}{{\\\\text d}x} = \\r\\n   \\\\begin{cases}\\r\\n   0 & x < 0\\\\\\\\\\r\\n   1 & x \\\\geq 0\\\\\\\\\\r\\n   \\\\end{cases}\\r\\n   \\\\tag{2}\\r\\n   $$\\r\\n\\r\\n   ```python\\r\\n   from torch.nn import functional as F\\r\\n   import torch\\r\\n   x = torch.linspace(-100, 100, 10)\\r\\n   F.relu(x)\\r\\n   ```\\r\\n\\r\\n3. Softmax\u51fd\u6570\\r\\n\\r\\n   \u5e38\u7528\u4e8e\u591a\u5206\u7c7b\u4efb\u52a1\uff0c\u7f51\u7edc\u7684\u8f93\u51fa\u7ecf\u8fc7Softmax\u51fd\u6570\u540e\uff0c\u6210\u4e3a\u548c\u4e3a1\u7684\u6982\u7387\\r\\n   $$\\r\\n   S(y_i) = \\\\frac{e^{y_i}}{\\\\sum_{j}^{n}{e^{y^j}}} \\\\tag{1}\\r\\n   $$\\r\\n\\r\\n## \u4e8c\u3001\u635f\u5931\u51fd\u6570\\r\\n\\r\\n1. Mean Squared Error \u5747\u65b9\u8bef\u5dee\\r\\n\\r\\n   - L2\u8303\u6570\u662f\u5bf9\u5143\u7d20\u6c42\u5e73\u65b9\u548c\u540e\u518d\u5f00\u6839\u53f7\uff0c\u9700\u8981.pow(2)\u540e\u624d\u53ef\u4f5c\u4e3a\u635f\u5931\u51fd\u6570\\r\\n   - \u5fae\u5c0f\u7684\u8bef\u5dee\u53ef\u80fd\u5bf9\u7f51\u7edc\u6027\u80fd\u5e26\u6765\u6781\u5927\u7684\u5f71\u54cd\\r\\n     $$\\r\\n     Loss_{MSE} = \\\\sum{[{y - f(x)]^2}}\\r\\n     \\\\tag{1}\\r\\n     $$\\r\\n\\r\\n     $$\\r\\n     \\\\Vert y - f(x) \\\\Vert_2 = \\\\sqrt[2]{\\\\sum{[y - f(x)]^2}}\\r\\n     \\\\tag{2}\\r\\n     $$\\r\\n   \\r\\n2. Cross Entropy Loss \u4ea4\u53c9\u71b5\u635f\u5931\\r\\n\\r\\n   - binary \u4e8c\u5206\u7c7b\u95ee\u9898\\r\\n   - multi-class \u591a\u5206\u7c7b\u95ee\u9898\\r\\n   - \u7ecf\u5e38\u4e0esoftmax\u6fc0\u6d3b\u51fd\u6570\u642d\u914d\u4f7f\u7528"},{"id":"/\u7406\u8bba\u77e5\u8bc6","metadata":{"permalink":"/blog/\u7406\u8bba\u77e5\u8bc6","source":"@site/blog/\u7406\u8bba\u77e5\u8bc6.md","title":"\u7406\u8bba\u57fa\u7840","description":"1. \u68af\u5ea6\u4e0b\u964d\u7b97\u6cd5\u9700\u8981\u6c42\u6574\u4e2a\u6570\u636e\u96c6\u4e0a\u7684\u8ba1\u7b97\u635f\u5931\u51fd\u6570\u4ee5\u53ca\u68af\u5ea6\uff0c\u8ba1\u7b97\u4ee3\u4ef7\u592a\u5927\uff0c\u56e0\u6b64\u5e38\u91c7\u7528\u5c0f\u6279\u91cf\u968f\u673a\u68af\u5ea6\u4e0b\u964d\u3002\u5728\u6bcf\u4e2abatch\u4e0a\u8ba1\u7b97\u635f\u5931\u51fd\u6570\u4ee5\u53ca\u68af\u5ea6\uff0c\u8fd1\u4f3c\u635f\u5931\u3002\u6b64\u65f6\uff0cbatchsize\u8d8a\u5927\uff0c\u8fd1\u4f3c\u6548\u679c\u8d8a\u597d\u3002","date":"2023-04-18T10:22:37.000Z","formattedDate":"2023\u5e744\u670818\u65e5","tags":[],"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","permalink":"/blog/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6"},"nextItem":{"title":"\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","permalink":"/blog/deep_learning/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6"}},"content":"1. \u68af\u5ea6\u4e0b\u964d\u7b97\u6cd5\u9700\u8981\u6c42\u6574\u4e2a\u6570\u636e\u96c6\u4e0a\u7684\u8ba1\u7b97\u635f\u5931\u51fd\u6570\u4ee5\u53ca\u68af\u5ea6\uff0c\u8ba1\u7b97\u4ee3\u4ef7\u592a\u5927\uff0c\u56e0\u6b64\u5e38\u91c7\u7528\u5c0f\u6279\u91cf\u968f\u673a\u68af\u5ea6\u4e0b\u964d\u3002\u5728\u6bcf\u4e2abatch\u4e0a\u8ba1\u7b97\u635f\u5931\u51fd\u6570\u4ee5\u53ca\u68af\u5ea6\uff0c\u8fd1\u4f3c\u635f\u5931\u3002\u6b64\u65f6\uff0cbatchsize\u8d8a\u5927\uff0c\u8fd1\u4f3c\u6548\u679c\u8d8a\u597d\u3002\\r\\n\\r\\n   \u968f\u673a\u68af\u5ea6\u4e0b\u964d\u7684\u968f\u673a\u6307\u7684\u5c31\u662f\u4f7f\u7528\u7684\u6570\u636e\u662f\u968f\u673a\u9009\u62e9\u7684mini batch\u6570\u636e\uff0c\u5373Mini-Batch Gradient Descent\u3002\\r\\n\\r\\n   \u7136\u800c\uff0cbatchsize\u8d8a\u5c0f\uff0c\u6536\u655b\u6548\u679c\u8d8a\u597d\u3002\u968f\u673a\u68af\u5ea6\u4e0b\u964d\u7406\u8bba\u4e0a\u5e26\u6765\u4e86\u566a\u97f3\uff0cbatchsize\u8f83\u5c0f\u65f6\u5e26\u6765\u7684\u566a\u97f3\u8f83\u5927\uff0c\u53ef\u4ee5\u589e\u52a0\u6a21\u578b\u7684\u9c81\u68d2\u6027\u3002\\r\\n\\r\\n2. \u524d\u5411\u4f20\u64ad\uff08Forward Propagation\uff09\uff1a\u5df2\u77e5\u6743\u91cd\u3001\u504f\u7f6e\u548c\u8f93\u5165\uff0c\u8ba1\u7b97\u51fa\u635f\u5931\u51fd\u6570\\r\\n\\r\\n   \u53cd\u5411\u4f20\u64ad\uff08Backward Propagation\uff09\uff1a\u6c42\u51fa\u635f\u5931\u51fd\u6570\u5bf9\u4e8e\u6bcf\u4e00\u4e2a\u6743\u91cd\u7684\u504f\u5bfc\\r\\n\\r\\n3. \u4ea4\u53c9\u71b5\u5e38\u6765\u7528\u4e8e\u8861\u91cf\u4e24\u4e2a\u6982\u7387\u4e4b\u95f4\u7684\u533a\u522b\\r\\n\\r\\n   \u4ea4\u53c9\u71b5\u635f\u5931\u51fd\u6570\u7684\u68af\u5ea6\u662f\u771f\u5b9e\u6982\u7387\u548c\u9884\u6d4b\u6982\u7387\u7684\u533a\u522b\\r\\n\\r\\n4. softmax\u6fc0\u6d3b\u51fd\u6570\u5e38\u7528\u4e8e\u591a\u5206\u7c7b\u95ee\u9898\u3002\u7ecf\u8fc7softmax\u51fd\u6570\u540e\u5f97\u5230\u7684\u8f93\u51fa\u4e3a\u4e00\u7ec4\u6982\u7387\uff0c\u6982\u7387\u975e\u8d1f\u4e14\u76f8\u52a0\u548c\u4e3a1\\r\\n\\r\\n5. \u9700\u8981\u770b\u7684\u8bba\u6587\uff1aResNet\uff0cU-Net\\r\\n\\r\\n6. \u8bad\u7ec3\u4f18\u5316\u65b9\u6cd5\uff1a\\r\\n\\r\\n   - \u521d\u59cb\u5316\uff1a\u607a\u660e\u521d\u59cb\u5316\u65b9\u6cd5\\r\\n   - \u5b66\u4e60\u7387\uff1a\\r\\n   - \u52a8\u91cf\uff1a\u9003\u51fa\u5c40\u90e8\u6700\u5c0f\u503c\uff0c\u53ef\u76f4\u89c2\u7406\u89e3\u4e3a\u60ef\u6027"},{"id":"/deep_learning/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","metadata":{"permalink":"/blog/deep_learning/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","source":"@site/blog/deep_learning/\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6.md","title":"\u6fc0\u6d3b\u51fd\u6570\u4e0eLoss\u7684\u68af\u5ea6","description":"\u4e00\u3001\u6fc0\u6d3b\u51fd\u6570","date":"2023-04-18T10:22:37.000Z","formattedDate":"2023\u5e744\u670818\u65e5","tags":[],"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"\u7406\u8bba\u57fa\u7840","permalink":"/blog/\u7406\u8bba\u77e5\u8bc6"}},"content":"## \u4e00\u3001\u6fc0\u6d3b\u51fd\u6570\\r\\n\\r\\n1. Sigmoid\u51fd\u6570 / Logistic\u51fd\u6570\\r\\n\\r\\n   $$\\r\\n   \\\\sigma(x) = \\\\frac{1}{1 + e^{-x}}\\r\\n   \\\\tag{1}\\r\\n   $$\\r\\n\\r\\n   $$\\r\\n   \\\\frac{{\\\\rm d}\\\\sigma}{{\\\\rm d}x} = \\\\sigma{(1 - \\\\sigma)}\\r\\n   \\\\tag{2}\\r\\n   $$\\r\\n\\r\\n\\r\\n   \u4f18\u70b9\uff1a\u53ef\u4ee5\u5c06\u6570\u636e\u538b\u7f29\u81f3[0, 1)\u533a\u95f4\u5185\uff0c\u6709\u8f83\u5927\u5b9e\u7528\u610f\u4e49\\r\\n\\r\\n   \u81f4\u547d\u95ee\u9898\uff1a\u5728\u8f93\u5165\u503c\u8f83\u5c0f\u6216\u8f83\u5927\u65f6\uff0cSigmoid\u51fd\u6570\u7684\u68af\u5ea6\u8d8b\u8fd1\u4e8e\u96f6\uff0c\u4f1a\u5bfc\u81f4\u7f51\u7edc\u53c2\u6570\u957f\u65f6\u95f4\u5f97\u4e0d\u5230\u66f4\u65b0\uff0c\u5373\u68af\u5ea6\u5f25\u6563\u95ee\u9898\\r\\n\\r\\n   ```python\\r\\n   from torch.nn import functional as F\\r\\n   import torch\\r\\n   x = torch.linspace(-100, 100, 10)\\r\\n   F.sigmoid(x)  # \u5f53x\u4e3a100\u65f6\uff0csigmoid(x)\u5c31\u63a5\u8fd1\u4e8e0\u4e86\\r\\n   ```\\r\\n\\r\\n2. \u7ebf\u6027\u6574\u6d41\u5355\u5143\uff08Rectified Linear Unit, ReLU\uff09\\r\\n   $$\\r\\n   f(x) = \\r\\n   \\\\begin{cases}\\r\\n   0 & x < 0\\\\\\\\\\r\\n   x & x \\\\geq 0\\\\\\\\\\r\\n   \\\\end{cases}\\r\\n   \\\\tag{1}\\r\\n   $$\\r\\n   $$\\r\\n   \\\\frac {{\\\\text d}f(x)}{{\\\\text d}x} = \\r\\n   \\\\begin{cases}\\r\\n   0 & x < 0\\\\\\\\\\r\\n   1 & x \\\\geq 0\\\\\\\\\\r\\n   \\\\end{cases}\\r\\n   \\\\tag{2}\\r\\n   $$\\r\\n\\r\\n   ```python\\r\\n   from torch.nn import functional as F\\r\\n   import torch\\r\\n   x = torch.linspace(-100, 100, 10)\\r\\n   F.relu(x)\\r\\n   ```\\r\\n\\r\\n3. Softmax\u51fd\u6570\\r\\n\\r\\n   \u5e38\u7528\u4e8e\u591a\u5206\u7c7b\u4efb\u52a1\uff0c\u7f51\u7edc\u7684\u8f93\u51fa\u7ecf\u8fc7Softmax\u51fd\u6570\u540e\uff0c\u6210\u4e3a\u548c\u4e3a1\u7684\u6982\u7387\\r\\n   $$\\r\\n   S(y_i) = \\\\frac{e^{y_i}}{\\\\sum_{j}^{n}{e^{y^j}}} \\\\tag{1}\\r\\n   $$\\r\\n\\r\\n## \u4e8c\u3001\u635f\u5931\u51fd\u6570\\r\\n\\r\\n1. Mean Squared Error \u5747\u65b9\u8bef\u5dee\\r\\n\\r\\n   - L2\u8303\u6570\u662f\u5bf9\u5143\u7d20\u6c42\u5e73\u65b9\u548c\u540e\u518d\u5f00\u6839\u53f7\uff0c\u9700\u8981.pow(2)\u540e\u624d\u53ef\u4f5c\u4e3a\u635f\u5931\u51fd\u6570\\r\\n   - \u5fae\u5c0f\u7684\u8bef\u5dee\u53ef\u80fd\u5bf9\u7f51\u7edc\u6027\u80fd\u5e26\u6765\u6781\u5927\u7684\u5f71\u54cd\\r\\n     $$\\r\\n     Loss_{MSE} = \\\\sum{[{y - f(x)]^2}}\\r\\n     \\\\tag{1}\\r\\n     $$\\r\\n\\r\\n     $$\\r\\n     \\\\Vert y - f(x) \\\\Vert_2 = \\\\sqrt[2]{\\\\sum{[y - f(x)]^2}}\\r\\n     \\\\tag{2}\\r\\n     $$\\r\\n   \\r\\n2. Cross Entropy Loss \u4ea4\u53c9\u71b5\u635f\u5931\\r\\n\\r\\n   - binary \u4e8c\u5206\u7c7b\u95ee\u9898\\r\\n   - multi-class \u591a\u5206\u7c7b\u95ee\u9898\\r\\n   - \u7ecf\u5e38\u4e0esoftmax\u6fc0\u6d3b\u51fd\u6570\u642d\u914d\u4f7f\u7528"}]}')}}]);